// Navegación y Menú Móvil
function toggleMenu() { const e = document.getElementById("mobile-menu"), t = document.getElementById("menu-button").querySelector("i"), n = "block" === e.style.display; e.style.display = n ? "none" : "block", n ? (t.classList.remove("fa-times"), t.classList.add("fa-bars")) : (t.classList.remove("fa-bars"), t.classList.add("fa-times")) }

// Animaciones de Entrada (Scroll Reveal)
const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.classList.add('reveal-active');
        }
    });
}, { threshold: 0.1 });

document.addEventListener('DOMContentLoaded', () => {
    // Aplicar animaciones a secciones
    const revealElements = document.querySelectorAll('section, .reveal-item');
    revealElements.forEach(el => {
        el.classList.add('reveal-init');
        observer.observe(el);
    });

    // Setup Menu
    const e = document.getElementById("menu-button");
    if (e) e.addEventListener("click", toggleMenu);

    // Form Handling
    const form = document.getElementById("contact-form");
    if (form) {
        form.addEventListener("submit", async function (t) {
            t.preventDefault();
            const n = new FormData(form), a = document.getElementById("form-status"), s = document.getElementById("submit-btn");
            s.disabled = !0;
            s.innerHTML = '<i class="fas fa-spinner fa-spin mr-2"></i> Enviando...';
            try {
                const t = await fetch(form.action, { method: form.method, body: n, headers: { Accept: "application/json" } });
                if (t.ok) {
                    a.innerHTML = '<div class="p-4 bg-green-500/20 text-green-400 rounded-xl border border-green-500/30">¡Mensaje enviado con éxito!</div>';
                    form.reset();
                } else {
                    a.innerHTML = '<div class="p-4 bg-red-500/20 text-red-400 rounded-xl border border-red-500/30">Error al enviar. Reintenta.</div>';
                }
            } catch (e) {
                a.innerHTML = '<div class="p-4 bg-red-500/20 text-red-400 rounded-xl border border-red-500/30">Error de conexión.</div>';
            } finally {
                s.disabled = !1;
                s.innerHTML = '<i class="fas fa-paper-plane mr-2"></i> Enviar Solicitud';
            }
        });
    }
});

// Canvas Background (Simplified/Fixed)
const canvas = document.getElementById("nodeCanvas");
if (canvas) {
    const ctx = canvas.getContext("2d");
    let w, h, particles = [];
    function resize() { w = canvas.width = window.innerWidth; h = canvas.height = window.innerHeight; }
    window.addEventListener("resize", resize);
    resize();
    class P {
        constructor() { this.x = Math.random() * w; this.y = Math.random() * h; this.vx = Math.random() - 0.5; this.vy = Math.random() - 0.5; }
        update() { this.x += this.vx; this.y += this.vy; if (this.x < 0 || this.x > w) this.vx *= -1; if (this.y < 0 || this.y > h) this.vy *= -1; }
        draw() { ctx.fillStyle = "rgba(34, 211, 238, 0.2)"; ctx.beginPath(); ctx.arc(this.x, this.y, 1.5, 0, Math.PI * 2); ctx.fill(); }
    }
    for (let i = 0; i < 50; i++) particles.push(new P());
    function loop() {
        ctx.clearRect(0, 0, w, h);
        particles.forEach(p => { p.update(); p.draw(); });
        requestAnimationFrame(loop);
    }
    loop();
}